               </div>
               {isSpellCheckExpanded && (
                   <div className="p-6">
                       <table className="min-w-full text-sm">
                           <thead>
                               <tr className="border-b dark:border-slate-700 text-left">
                                   <th className="py-2 text-slate-500">Termo Original</th>
                                   <th className="py-2 text-slate-500">Sugestão IA</th>
                                   <th className="py-2 text-slate-500">Confiança</th>
                               </tr>
                           </thead>
                           <tbody>
                               {validSpellCheck.map((item, idx) => (
                                   <tr key={idx} className="border-b dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700/50">
                                       <td className="py-2 font-mono text-red-600 dark:text-red-400">{item.original_term}</td>
                                       <td className="py-2 font-bold text-green-600 dark:text-green-400">{item.suggested_correction}</td>
                                       <td className="py-2"><span className="px-2 py-1 rounded bg-slate-100 dark:bg-slate-700 text-xs">{item.confidence}</span></td>
                                   </tr>
                               ))}
                           </tbody>
                       </table>
                   </div>
               )}
          </div>
      )}

      {/* DRE IFRS SECTION */}
      {summary.document_type === 'DRE' && (
        <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden print:hidden">
             <div className="px-6 py-4 bg-slate-100 dark:bg-slate-900 border-b dark:border-slate-700 flex justify-between items-center">
