            </div>
            <div className="flex items-end">
                <div className="flex items-center space-x-2 border p-2 rounded w-full bg-white dark:bg-slate-800 dark:border-slate-600 h-[42px]">
                    <input 
                        type="checkbox" 
                        id="toggleSuggestionCol" 
