                        onChange={(e) => setShowSuggestionCol(e.target.checked)} 
                        className="w-4 h-4 text-purple-600 rounded focus:ring-purple-500 bg-slate-100 border-slate-300" 
                    />
                    <label htmlFor="toggleSuggestionCol" className="text-sm cursor-pointer select-none text-slate-700 dark:text-slate-300">
                        Exibir Coluna "Sugestão IA"
                    </label>
                </div>
            </div>
         </div>}

         <div className="overflow-auto max-h-[70vh] print:max-h-none">
          <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
            <thead className="bg-slate-100 dark:bg-slate-900 sticky top-0 z-20 shadow-md">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-medium text-slate-500 uppercase bg-slate-100 dark:bg-slate-900">Código</th>
                <th className="px-4 py-3 text-left text-xs font-medium text-slate-500 uppercase bg-slate-100 dark:bg-slate-900">Conta</th>
                {showSuggestionCol && <th className="px-4 py-3 text-left text-xs font-medium text-purple-600 uppercase bg-slate-100 dark:bg-slate-900">Sugestão IA</th>}
                <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 uppercase bg-slate-100 dark:bg-slate-900">Sdo. Anterior</th>
                <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 uppercase bg-slate-100 dark:bg-slate-900">Débito</th>
                <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 uppercase bg-slate-100 dark:bg-slate-900">Crédito</th>
                <th className="px-4 py-3 text-right text-xs font-medium text-slate-500 uppercase bg-slate-100 dark:bg-slate-900">Sdo. Atual</th>
                <th className="px-4 py-3 text-center text-xs font-medium text-slate-500 uppercase bg-slate-100 dark:bg-slate-900">Inv.</th>
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                  {paginatedAccounts.map((account) => {
                        const suggestion = getSuggestionForAccount(account);
                        return (
                        <tr key={account.originalIndex} className={`hover:bg-slate-50 dark:hover:bg-slate-700 ${account.possible_inversion ? 'bg-yellow-50 dark:bg-yellow-900/10 border-l-[6px] border-yellow-500' : ''} ${account.is_synthetic ? 'bg-slate-50 dark:bg-slate-700/30 font-bold' : ''}`}>
                          <td className="px-4 py-3 whitespace-nowrap text-sm font-mono text-blue-600 font-bold">
                             {account.account_code ? <a href={`https://www.google.com/search?q=${encodeURIComponent(account.account_code + ' ' + account.account_name)}`} target="_blank" rel="noreferrer" className="hover:underline">{account.account_code}</a> : '-'}
                          </td>
                          <td className="px-4 py-3 text-sm dark:text-white relative">
                            <div className="flex items-center" style={{ paddingLeft: `${(account.level - 1) * 16}px` }}>
                                {account.is_synthetic && (
                                    <button onClick={() => account.account_code && toggleGroup(account.account_code)} className="mr-2 w-4 h-4 flex items-center justify-center border rounded bg-slate-200 dark:bg-slate-600 text-xs print:hidden">
                                        {account.account_code && expandedGroups.has(account.account_code) ? '-' : '+'}
                                    </button>
                                )}
                                <span className={account.possible_inversion ? 'underline decoration-red-500 decoration-wavy' : ''}>
                                    {showCorrectedNames ? getDisplayedName(account) : account.account_name}
                                </span>

                                {/* GRAPHICAL SUGGESTION INDICATOR */}
                                {!showCorrectedNames && suggestion && (
                                    <div className="group relative ml-2 cursor-help print:hidden">
                                        <span className="text-purple-500 animate-pulse text-lg" title="Sugestão de Correção Disponível">✨</span>
                                        <div className="absolute left-full top-0 ml-2 w-64 bg-white dark:bg-slate-800 border border-purple-200 dark:border-purple-600 shadow-xl rounded p-3 text-xs z-50 hidden group-hover:block">
                                            <p className="font-bold text-purple-700 dark:text-purple-300 mb-1 border-b pb-1">Sugestão Ortográfica IA:</p>
                                            <p className="line-through text-slate-400 mb-1">{account.account_name}</p>
                                            <p className="text-green-600 dark:text-green-400 font-bold text-sm">⬇ {suggestion}</p>
                                        </div>
                                    </div>
                                )}

                                {showCorrectedNames && suggestion && (
                                     <span className="ml-2 text-[10px] bg-purple-100 dark:bg-purple-900 text-purple-600 dark:text-purple-300 px-1 rounded border border-purple-200 dark:border-purple-700">Corrigido</span>
                                )}
                            </div>
                          </td>
                          {showSuggestionCol && <td className="px-4 py-3 text-sm text-green-600 font-medium">{getSuggestionForAccount(account) || '-'}</td>}
                          <td className="px-4 py-3 text-right text-sm font-mono">{formatCurrency(account.initial_balance)}</td>
                          <td className="px-4 py-3 text-right text-sm text-blue-700 dark:text-blue-300 font-mono">{account.debit_value > 0 ? formatCurrency(account.debit_value) : '-'}</td>
                          <td className="px-4 py-3 text-right text-sm text-red-700 dark:text-red-300 font-mono">{account.credit_value > 0 ? formatCurrency(account.credit_value) : '-'}</td>
                          <td className="px-4 py-3 text-right text-sm font-mono bg-slate-50/50 dark:bg-slate-700/50">{formatCurrency(account.final_balance)}</td>
                          <td className={`px-4 py-3 text-center ${account.possible_inversion ? 'bg-yellow-100 dark:bg-yellow-900/40 rounded' : ''}`}>
                              {account.possible_inversion && !account.is_synthetic && (
                                  <div className="group relative inline-block cursor-help print:hidden">
                                      <span className="text-yellow-600 dark:text-yellow-400 font-bold text-lg">⚠️</span>
                                      <div className="absolute right-0 top-full mt-2 w-72 bg-white dark:bg-slate-800 border-2 border-yellow-400 dark:border-yellow-600 shadow-xl rounded-lg p-4 text-left z-50 hidden group-hover:block animate-fadeIn">
                                          <h4 className="font-bold text-yellow-700 dark:text-yellow-500 text-sm uppercase mb-3 border-b border-yellow-200 pb-2 flex items-center">
                                             <span className="mr-2 text-xl">⚠️</span> Inversão de Natureza
                                          </h4>
                                          <p className="text-xs mb-3 text-slate-700 dark:text-slate-300 leading-relaxed font-medium">
                                             Esta conta está com saldo final contrário ao esperado para seu grupo contábil.
                                          </p>
                                          <div className="bg-yellow-50 dark:bg-yellow-900/30 p-3 rounded border border-yellow-200 dark:border-yellow-700/50 mb-3">
                                              <p className="text-[10px] font-extrabold text-yellow-800 dark:text-yellow-400 mb-2 uppercase tracking-wide">Exemplos Concretos:</p>
                                              <ul className="space-y-2">
                                                  <li className="text-xs text-slate-800 dark:text-slate-200 flex items-start">
                                                      <span className="text-red-500 mr-1">❌</span>
                                                      <span><strong>Caixa/Bancos (Ativo)</strong><br/><span className="text-[10px] opacity-80">Virou CREDOR (Negativo/Estourado)</span></span>
                                                  </li>
                                                  <li className="text-xs text-slate-800 dark:text-slate-200 flex items-start">
                                                      <span className="text-red-500 mr-1">❌</span>
                                                      <span><strong>Fornecedores (Passivo)</strong><br/><span className="text-[10px] opacity-80">Virou DEVEDOR (Adiantamento?)</span></span>
                                                  </li>
                                              </ul>
                                          </div>
                                          <p className="text-xs text-blue-600 dark:text-blue-400 font-bold border-t pt-2 border-slate-100 dark:border-slate-700">
                                              👉 Ação: Verifique erros de classificação ou lançamentos manuais invertidos.
                                          </p>
                                      </div>
                                  </div>
                              )}
                          </td>
                        </tr>
                  )})}
            </tbody>
          </table>
         </div>
      </div>
    </div>
  );
};

export default AnalysisViewer;

import React, { useState, useMemo } from 'react';
import { HistoryItem } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  history: HistoryItem[];
  onSelect: (item: HistoryItem) => void;
  onClear: () => void;
  currentUser?: string;
}

const AnalysisHistory: React.FC<Props> = ({ isOpen, onClose, history, onSelect, onClear, currentUser }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'all' | 'mine'>('all');

  const formatDate = (isoString: string) => {
    return new Date(isoString).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const filteredHistory = useMemo(() => {
    let data = history;

    if (viewMode === 'mine' && currentUser) {
        data = data.filter(item => 
            item.headerData.collaboratorName && 
            item.headerData.collaboratorName.toLowerCase().trim() === currentUser.toLowerCase().trim()
        );
    }

    if (!searchTerm.trim()) {
      return data;
    }
    const lowercasedFilter = searchTerm.toLowerCase();
    return data.filter(item =>
      (item.headerData.collaboratorName && item.headerData.collaboratorName.toLowerCase().includes(lowercasedFilter)) ||
      (item.headerData.companyName && item.headerData.companyName.toLowerCase().includes(lowercasedFilter)) ||
      (item.fileName && item.fileName.toLowerCase().includes(lowercasedFilter)) ||
      formatDate(item.timestamp).includes(lowercasedFilter)
    );
  }, [history, searchTerm, viewMode, currentUser]);


  return (
    <div className={`fixed inset-0 z-50 overflow-hidden transition-all duration-300 ${isOpen ? 'pointer-events-auto' : 'pointer-events-none'}`}>
      {/* Backdrop */}
      <div 
        className={`absolute inset-0 bg-slate-900/50 backdrop-blur-sm transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`}
        onClick={onClose}
      />

      {/* Sidebar */}
      <div className={`absolute inset-y-0 right-0 max-w-md w-full bg-white dark:bg-slate-800 shadow-2xl flex flex-col transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        {/* Header */}
        <div className="px-6 py-4 bg-slate-100 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-700 flex items-center justify-between">
          <h2 className="text-lg font-semibold text-slate-800 dark:text-white flex items-center">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-5 h-5 mr-2 text-blue-600 dark:text-blue-400">
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6h4.5m4.5 0a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            Histórico de Consultas
          </h2>
          <button onClick={onClose} className="text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-white p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* FILTERS */}
        <div className="px-4 pt-4 bg-slate-50 dark:bg-slate-800/50">
            <div className="flex bg-slate-200 dark:bg-slate-700 rounded-lg p-1 mb-3">
                <button 
                    onClick={() => setViewMode('all')} 
                    className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${
                        viewMode === 'all' 
                        ? 'bg-white dark:bg-slate-600 text-blue-600 dark:text-blue-300 shadow-sm' 
                        : 'text-slate-500 dark:text-slate-400 hover:text-slate-700'
                    }`}
                >
                    Todas Análises
                </button>
                <button 
                    onClick={() => setViewMode('mine')} 
                    disabled={!currentUser}
                    title={!currentUser ? "Defina um colaborador na tela inicial" : ""}
                    className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${
                        viewMode === 'mine' 
                        ? 'bg-white dark:bg-slate-600 text-blue-600 dark:text-blue-300 shadow-sm' 
                        : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 disabled:opacity-40 disabled:cursor-not-allowed'
                    }`}
                >
                    Meus Relatórios {currentUser ? `(${currentUser.split(' ')[0]})` : ''}
                </button>
            </div>

            <div className="relative mb-2">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4 text-slate-400">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.607 10.607z" />
                </svg>
                </div>
                <input
                type="text"
                placeholder="Filtrar por nome, empresa ou data..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-9 pr-4 py-2 border border-slate-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                />
            </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-4 bg-slate-50 dark:bg-slate-800/50">
          {history.length === 0 ? (
            <div className="text-center py-12 text-slate-500 dark:text-slate-400">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-16 h-16 mx-auto mb-4 opacity-30">
                <path strokeLinecap="round" strokeLinejoin="round" d="M20.25 7.5l-.625 10.632a2.25 2.25 0 01-2.247 2.118H6.622a2.25 2.25 0 01-2.247-2.118L3.75 7.5m8.25 3v6.75m0 0l-3-3m3 3l3-3M3.375 7.5h17.25c.621 0 1.125-.504 1.125-1.125v-1.5c0-.621-.504-1.125-1.125-1.125H3.375c-.621 0-1.125.504-1.125 1.125v1.5c0 .621.504 1.125 1.125 1.125z" />
              </svg>
              <p>Nenhuma análise salva ainda.</p>
            </div>
          ) : filteredHistory.length === 0 ? (
             <div className="text-center py-12 text-slate-500 dark:text-slate-400">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-16 h-16 mx-auto mb-4 opacity-30">
