// Helper for Exponential Backoff
async function retryWithBackoff<T>(fn: () => Promise<T>, retries = 3, baseDelay = 3000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const message = error?.message || '';
    const status = error?.status || error?.code;

    // 404 Model Not Found - Do not retry specific model errors
    if (message.includes('404') || message.includes('not found')) {
        throw error;
    }

    if (retries > 0) {
      console.warn(`API Error (${status}). Retrying in ${baseDelay}ms...`);
      await new Promise(resolve => setTimeout(resolve, baseDelay));
      return retryWithBackoff(fn, retries - 1, baseDelay * 2);
    }
    throw error;
  }
}

// --- ROBUST FINANCIAL NUMBER PARSER (MULTI-FORMAT) ---
function parseFinancialNumber(val: any): number {
  if (typeof val === 'number') return val;
  if (!val) return 0;

  if (typeof val === 'string') {
    let clean = val.trim();
    // Remove currency and noise
    clean = clean.replace(/[R$]/gi, '').trim();
    // Common OCR errors: l, O, I => 1, 0, 1
    clean = clean.replace(/[OolI]/g, (m) => m === 'I' || m === 'l' ? '1' : '0'); 

    // Remove D/C suffix
    clean = clean.replace(/[DC]$/i, ''); 

    // Remove parens often used for negative numbers: (100) -> -100
    const isNegativeParens = /^\(.*\)$/.test(clean);
    clean = clean.replace(/[()]/g, '');

    // Normalize Spaces
    clean = clean.replace(/\s+/g, '');

    // HEURISTIC: Detect Format (Comma vs Dot Decimal)
    // 1. If multiple dots and one comma at end: 1.000,00 (BR)
    // 2. If multiple commas and one dot at end: 1,000.00 (US)
    // 3. If just one comma: 100,00 (BR) or 1,000 (US int)
    // 4. If just one dot: 100.00 (US) or 1.000 (BR int)

    const lastCommaIndex = clean.lastIndexOf(',');
    const lastDotIndex = clean.lastIndexOf('.');

    let isBRFormat = true; // Default assumption

    if (lastCommaIndex > -1 && lastDotIndex > -1) {
        if (lastDotIndex > lastCommaIndex) isBRFormat = false; // US: 1,000.00
    } else if (lastCommaIndex > -1 && lastDotIndex === -1) {
        // Only comma. 
        // If it looks like 1,000 (comma followed by 3 digits exactly and end of string or space), it might be US int separator.
        // But in BR accounting, 1,000 is 1.0. We assume BR decimal separator unless context suggests otherwise.
        // However, if we stripped thousands, we check context.
        // Safe bet: Comma is decimal in BR.
        isBRFormat = true; 
    } else if (lastDotIndex > -1 && lastCommaIndex === -1) {
        // Only dot. 
        // 1.000 -> Is it 1000 or 1?
        // Usually OCR returns 1000.00.
        // If it has 3 digits after dot, it's ambiguous.
        // We will assume US format if only dots exist to support US-style outputs from Gemini or Excel-CSV.
        // Wait, Excel CSV often uses '.' for decimal if generic, or ',' if BR locale.
        // Let's assume Dot is Decimal if Comma is missing, UNLESS it looks like a thousand separator (1.000).
        if (clean.match(/^\d{1,3}(\.\d{3})+$/)) {
            // It matches 1.000 or 1.000.000 structure perfectly -> It's an integer with thousand separators (BR)
            clean = clean.replace(/\./g, '');
            isBRFormat = false; // It's now clean int
        } else {
             isBRFormat = false; // It's 100.50
        }
    }

    if (isBRFormat) {
        clean = clean.replace(/\./g, ''); // Remove thousand dots
        clean = clean.replace(',', '.');  // Decimal comma to dot
    } else {
        clean = clean.replace(/,/g, ''); // Remove thousand commas
    }

    // Final cleanup
    clean = clean.replace(/[^0-9.-]/g, '');

    let num = parseFloat(clean);
    if (isNegativeParens) num = -Math.abs(num);

    return isNaN(num) ? 0 : num;
  }
  return 0;
}

// --- LOGIC TO DETECT INVERSIONS ---
function checkInversion(name: string, type: 'Debit' | 'Credit', finalBalance: number): boolean {
    const lower = name.toLowerCase();

    // Assets & Expenses (Debit Nature)
    if (lower.includes('caixa') || lower.includes('banco') || lower.includes('cliente') || lower.includes('ativo') || lower.includes('estoque') || lower.includes('despesa') || lower.includes('custo')) {
        if (type === 'Credit' && finalBalance > 0) return true;
        if (type === 'Debit' && finalBalance < 0) return true;
    }

    // Liabilities & Revenue (Credit Nature)
    if (lower.includes('fornecedor') || lower.includes('pagar') || lower.includes('imposto') || lower.includes('capital') || lower.includes('receita') || lower.includes('passivo') || lower.includes('patrimonio')) {
        if (type === 'Debit' && finalBalance > 0) return true;
        if (type === 'Credit' && finalBalance < 0) return true;
    }

    return false;
}

// --- SMART COLUMN MAPPER ---
function mapValuesToColumns(numbers: number[], type: 'Debit' | 'Credit'): { initial: number, debit: number, credit: number, final: number } {
    const count = numbers.length;
    let initial = 0, debit = 0, credit = 0, final = 0;

    if (count >= 4) {
        [initial, debit, credit, final] = numbers.slice(-4);
    } else if (count === 3) {
        [debit, credit, final] = numbers;
    } else if (count === 2) {
        [debit, credit] = numbers;
    } else if (count === 1) {
        final = numbers[0];
    }

    // Validation
    const tolerance = 0.05;
    const calcDebitNature = initial + debit - credit;
    if (Math.abs(calcDebitNature - final) < tolerance) return { initial, debit, credit, final };

    const calcCreditNature = initial + credit - debit;
    if (Math.abs(calcCreditNature - final) < tolerance) return { initial, debit, credit, final };

    const calcDebitSwap = initial + credit - debit; 
    if (Math.abs(calcDebitSwap - final) < tolerance) return { initial, debit: credit, credit: debit, final };

    return { initial, debit, credit, final };
}

// --- DATA NORMALIZATION & ANALYSIS ---
function normalizeFinancialData(rawLines: string[], docType: string): AnalysisResult {
  const accounts: ExtractedAccount[] = [];

  // Updated Regex: Permissive for both BR (1.000,00) and US (1,000.00) and plain (1000)
  // Catch integers or decimals, positive or negative
  const numberPattern = /-?\(?[\d]+(?:[.,]\d{3})*(?:[.,]\d+)?\)?/g;

  let explicitResultValue: number | undefined = undefined;
  let explicitResultLabel: string | undefined = undefined;

  rawLines.forEach(line => {
      // Handle Pipe Separator (CSV/Table)
      const isPipe = line.includes('|');
      let cleanLine = line.replace(/;/g, ' ').trim();
      if (isPipe) {
          // If pipe separated, assume structure: Code | Name | Val1 | Val2 ...
          // OR Code Name | Val1 | Val2
          cleanLine = line.replace(/\|/g, '   '); // Replace pipe with triple space to ensure separation
      }

      if (cleanLine.length < 3) return;

      // 1. Extract all numbers
      const allNumbersMatch = cleanLine.match(numberPattern) || [];
      const parsedNumbers = allNumbersMatch.map(n => parseFinancialNumber(n)).filter(n => !isNaN(n));

      // 2. Isolate Text Part
      let textPart = cleanLine;
      for (const numStr of allNumbersMatch) {
          // Replace only if it's not part of the start (Account Code)
          // Heuristic: If numStr is at the end of the line, remove it.
          const lastIndex = textPart.lastIndexOf(numStr);
          if (lastIndex > 5) { 
             textPart = textPart.substring(0, lastIndex) + textPart.substring(lastIndex + numStr.length);
          }
      }
      textPart = textPart.trim();
      textPart = textPart.replace(/\s{2,}/g, ' '); // Collapse spaces

      // 3. Split Code and Name
      const parts = textPart.split(' ');
      let code = '';
      let name = '';

      // Check if first part looks like a code (digits, dots, hyphens)
      if (parts.length > 0 && /^[\d.-]+$/.test(parts[0]) && parts[0].length > 1) {
          code = parts[0];
          name = parts.slice(1).join(' ');
      } else {
           const lowerText = textPart.toLowerCase();
           if (lowerText.includes('lucro') || lowerText.includes('prejuízo') || lowerText.includes('resultado')) {
                code = ''; 
                name = textPart; 
           } else {
                name = textPart;
           }
      }

      // If we stripped ALL numbers including the code by accident (e.g. code 1000), restore if name is empty
      if (!name && parsedNumbers.length > 0) {
          // This is a heuristic guess
          // name = "Conta Desconhecida"; 
      }

      if (name.length < 2) return;

      // Determine Nature
      let type: 'Debit' | 'Credit' = 'Debit';
      const lowerName = name.toLowerCase();
      if (lowerName.includes('passivo') || lowerName.includes('receita') || lowerName.includes('fornecedor') || lowerName.includes('patrimonio') || lowerName.includes('obriga') || lowerName.includes('capital')) {
          type = 'Credit';
      }

      // Map Columns (Using only valid numbers found)
      // heuristic: if first parsed number matches code numerically, remove it from values.
      if (code && parsedNumbers.length > 0) {
           const codeNum = parseFloat(code.replace(/[.-]/g, ''));
           if (Math.abs(parsedNumbers[0] - codeNum) < 0.001) {
               parsedNumbers.shift();
           }
      }

      const values = mapValuesToColumns(parsedNumbers, type);

      const level = code ? code.split(/[.-]/).length : 1;
      let isSynthetic = false;
      if (level <= 2 && code.length > 0) isSynthetic = true;
      if (name === name.toUpperCase() && name.length > 5 && !name.includes('LUCRO')) isSynthetic = true; 
      if (lowerName.startsWith('total') || lowerName.startsWith('soma')) isSynthetic = true;

      if (lowerName.includes('lucro') || lowerName.includes('prejuízo') || lowerName.includes('resultado do')) {
          isSynthetic = false; 
          if (lowerName.includes('líquido') || lowerName.includes('exercício')) {
             explicitResultValue = values.final;
             explicitResultLabel = name;
          }
      }

      let category = null;
      if (docType === 'DRE') {
           if (lowerName.includes('receita') || lowerName.includes('custo') || lowerName.includes('despesa')) category = 'Operacional';
           else if (lowerName.includes('invest') || lowerName.includes('imobiliz')) category = 'Investimento';
           else if (lowerName.includes('juro') || lowerName.includes('financ')) category = 'Financiamento';
           else category = 'Operacional';
      }

      const possibleInversion = checkInversion(name, type, values.final);

      accounts.push({
          account_code: code,
          account_name: name,
          initial_balance: values.initial,
          debit_value: values.debit,
          credit_value: values.credit,
          final_balance: values.final,
          total_value: values.final,
          type,
          possible_inversion: possibleInversion,
          ifrs18_category: category as any,
          level,
          is_synthetic: isSynthetic
      });
  });

  const total_debits = accounts.reduce((sum, a) => sum + (a.is_synthetic ? 0 : a.debit_value), 0);
  const total_credits = accounts.reduce((sum, a) => sum + (a.is_synthetic ? 0 : a.credit_value), 0);
  const discrepancy = Math.abs(total_debits - total_credits);

  return {
      summary: {
          document_type: docType as any,
          period: 'A definir',
          total_debits,
          total_credits,
          is_balanced: discrepancy < 1.0,
          discrepancy_amount: discrepancy,
          observations: [],
          specific_result_value: explicitResultValue,
          specific_result_label: explicitResultLabel
      },
      accounts,
      spell_check: []
  };
}

// --- STEP 1: RAW EXTRACTION ---
async function extractRawData(ai: GoogleGenAI, fileBase64: string, mimeType: string): Promise<{lines: string[], docType: string}> {

    const safetySettings = [
        { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
        { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
        { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE },
        { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
    ];

    // UPDATED PROMPT: Request Pipe Separators for better parsing
    const promptText = `
    ROLE: OCR/Data Extractor.
    TASK: Convert document financial tables to structured TEXT lines.

    RULES:
    1. EXTRACT rows with account data.
    2. USE '|' (PIPE) to separate columns if possible, OR keep original spacing.
    3. KEEP original number formatting (e.g. 1.000,00 or 1,000.00).
    4. IGNORE Page headers/footers.
    5. OUTPUT FORMAT example: "1.01 | Caixa Geral | 1000,00"
    `;

    try {
        console.log("Starting Extraction...");
        const response = await retryWithBackoff<GenerateContentResponse>(() => ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: { parts: [{ inlineData: { mimeType: mimeType, data: fileBase64 } }, { text: promptText }] },
            config: { temperature: 0.1, maxOutputTokens: 8192, safetySettings: safetySettings }
        }));

        let text = response.text || '';

        // Fallback for empty text (rare but happens with bad PDF encoding)
        if (text.length < 50) {
             console.warn("Retrying with JSON mode...");
             const responseRetry = await retryWithBackoff<GenerateContentResponse>(() => ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: { parts: [{ inlineData: { mimeType: mimeType, data: fileBase64 } }, { text: "List all accounts as JSON array of strings: ['Code Name | Value', ...]" }] },
                config: { temperature: 0.1, maxOutputTokens: 8192, safetySettings: safetySettings }
            }));
            const jsonText = responseRetry.text || '[]';
            const match = jsonText.match(/\[.*\]/s);
            if (match) {
                try {
                    const jsonLines = JSON.parse(match[0]);
                    if (Array.isArray(jsonLines)) text = jsonLines.join('\n');
                } catch (e) { text = jsonText; }
            } else {
                text = jsonText;
            }
        }

        // Filter empty lines
        const lines = text.split('\n').filter(l => l.trim().length > 0 && /\d/.test(l)); 

        let docType = 'Balancete';
        if (text.toLowerCase().includes('resultado') || text.toLowerCase().includes('receita operacional')) docType = 'DRE';
        if (text.toLowerCase().includes('ativo') && text.toLowerCase().includes('passivo')) docType = 'Balanço Patrimonial';

        return { lines, docType };

    } catch (e) {
        console.error("Extraction Error:", e);
        throw new Error("O modelo não retornou dados. O documento pode estar ilegível.");
    }
}

// --- STEP 2: NARRATIVE ANALYSIS (UNCHANGED) ---
async function generateNarrativeAnalysis(ai: GoogleGenAI, summaryData: any, sampleAccounts: string[]): Promise<{observations: string[], spellcheck: any[], period: string}> {
    const prompt = `
    ATUE COMO: Auditor Contábil.
    IDIOMA: PORTUGUÊS (BRASIL).

    ANALISE ESTES DADOS TOTAIS:
    - Documento: ${summaryData.document_type}
    - Total Débito: ${summaryData.total_debits}
    - Total Crédito: ${summaryData.total_credits}
    - Diferença: ${summaryData.discrepancy_amount}
    - Resultado Específico Encontrado: ${summaryData.specific_result_label || 'Nenhum'} (${summaryData.specific_result_value || 0})

    AMOSTRA DE CONTAS:
    ${sampleAccounts.join('; ')}

    SAÍDA JSON:
    {
      "period": "dd/mm/aaaa a dd/mm/aaaa",
      "observations": [ "Análise narrativa do resultado...", "Explicação sobre o desbalanceamento (se houver)..." ],
      "spell_check": [ { "original_term": "Termo", "suggested_correction": "Correção", "confidence": "High" } ]
    }
    `;

    try {
        const response = await retryWithBackoff<GenerateContentResponse>(() => ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: { parts: [{ text: prompt }] },
            config: { responseMimeType: "application/json", temperature: 0.4 }
        }));

        return JSON.parse(response.text || '{}');
    } catch (e) {
        return { observations: ["Análise narrativa indisponível."], spellcheck: [], period: "Indefinido" };
    }
}

export const analyzeDocument = async (fileBase64: string, mimeType: string): Promise<AnalysisResult> => {
  if (!process.env.API_KEY) throw new Error("API Key not found.");
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // 1. RAW EXTRACTION
  const { lines, docType } = await extractRawData(ai, fileBase64, mimeType);

  if (lines.length === 0) throw new Error("Nenhum dado encontrado no arquivo.");

  // 2. NORMALIZE & CALCULATE
  const result = normalizeFinancialData(lines, docType);

  // If normalization failed to find any accounts
  if (result.accounts.length === 0) {
      throw new Error("O arquivo foi lido, mas nenhuma conta contábil válida foi identificada. Verifique se o formato é legível.");
  }

  // 3. NARRATIVE
  const sample = result.accounts.slice(0, 50).map(a => `${a.account_name} (${a.final_balance})`);
  const narrative = await generateNarrativeAnalysis(ai, result.summary, sample);

  result.summary.period = narrative.period || 'Período não identificado';
  result.summary.observations = narrative.observations || [];
  result.spell_check = narrative.spellcheck || [];

  return result;
};

