                 <div className="flex gap-2">
                     <button onClick={expandAllIFRS} disabled={!hasIFRSData} className="px-3 py-1 rounded bg-slate-200 disabled:opacity-50 text-xs hover:bg-slate-300 text-slate-700">Expandir Tudo</button>
